// ============================================================================
// BUILD REQUEST - Prepare prompt for Gemini Veo-3
// ============================================================================

const input = $input.first().json;

// Extract prompt from various possible input fields
const promptText = input.prompt_text || input.prompt || input.query || input.description || 'A beautiful cinematic video';

// Clean the prompt - remove any problematic characters
const cleanPrompt = promptText
  .replace(/[\n\r]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 1000); // Limit prompt length

// Optional parameters
const duration = input.duration || 5;
const hasImage = !!(input.image_base64 || input.image_url);

return [{
  json: {
    clean_prompt: cleanPrompt,
    original_prompt: promptText,
    duration: duration,
    has_image: hasImage,
    promptImage: input.image_base64 || input.image_url || null,
    promptText: cleanPrompt
  }
}];

// ============================================================================
// EXTRACT VIDEO URL FROM CLOUDINARY RESPONSE (V3)
// ============================================================================
// Cloudinary retourne un JSON avec secure_url, url, public_id, etc.
// ============================================================================

const response = $input.first().json;
const buildData = $('Build Request').item.json;

// Cloudinary response structure:
// {
//   "secure_url": "https://res.cloudinary.com/xxx/video/upload/v123/folder/video.mp4",
//   "url": "http://res.cloudinary.com/xxx/video/upload/v123/folder/video.mp4",
//   "public_id": "agency-killer/videos/abc123",
//   "format": "mp4",
//   "resource_type": "video",
//   "duration": 5.2,
//   "width": 1920,
//   "height": 1080
// }

const videoUrl = response.secure_url || response.url || null;

if (!videoUrl) {
  console.error('Cloudinary response:', JSON.stringify(response));
  throw new Error('Video upload to Cloudinary failed. Response: ' + JSON.stringify(response));
}

return [{
  json: {
    success: true,
    video_url: videoUrl,
    public_id: response.public_id || null,
    provider: 'cloudinary',
    format: response.format || 'mp4',
    duration: response.duration || null,
    width: response.width || null,
    height: response.height || null,
    script: buildData.original_prompt,
    clean_prompt: buildData.clean_prompt,
    mime_type: 'video/mp4'
  }
}];

// ============================================================================
// SUCCESS OUTPUT - Format final response for Creative V6
// ============================================================================

const videoData = $input.first().json;

return [{
  json: {
    success: true,
    tool: 'veo3_video_generator',
    video: {
      url: videoData.video_url,
      script: videoData.script,
      prompt_used: videoData.clean_prompt,
      provider: 'cloudinary',
      public_id: videoData.public_id,
      format: videoData.format,
      duration: videoData.duration,
      width: videoData.width,
      height: videoData.height,
      mime_type: videoData.mime_type,
      downloadable: true
    },
    // Pour le frontend - UI Component (MÊME FORMAT QUE AVANT)
    ui_component: 'AD_PREVIEW',
    ui_data: {
      video_url: videoData.video_url,
      script: videoData.script,
      title: 'Video generee par Veo-3',
      downloadable: true
    },
    // Format Creative V6 (MÊME FORMAT QUE AVANT)
    video_url: videoData.video_url,
    prompt_used: videoData.clean_prompt,
    generated_at: new Date().toISOString()
  }
}];

// ============================================================================
// ERROR HANDLER - Format error response
// ============================================================================

const error = $input.first().json;

return [{
  json: {
    success: false,
    tool: 'veo3_video_generator',
    error: {
      message: error.message || 'Video generation failed',
      details: JSON.stringify(error)
    },
    video: null,
    generated_at: new Date().toISOString()
  }
}];
